/**
 * API Routes Index
 *
 * Central export for all route modules.
 */

export { authRoutes } from './auth';
export { fleetRoutes } from './fleet';
export { pmScheduleRoutes } from './pm-schedule';
export { mileageRoutes } from './mileage';
export { optimizerRoutes } from './optimizer';
export { baselineRoutes } from './baseline';
export { driftRoutes } from './drift';
export { manhourRoutes } from './manhour';
export { canvasRoutes } from './canvas';
export { costingRoutes } from './costing';
export { materialRoutes } from './material';
export { scenarioRoutes } from './scenario';
export { exportRoutes } from './export';
export { integrationRoutes } from './integration';
export { baselineAssumptionRoutes } from './baseline-assumption';

/**
 * MMS API Server Entry Point
 *
 * Starts the Hono server using Bun runtime.
 * Use this file to start the API server standalone.
 *
 * Usage: bun run src/api/server.ts
 *
 * Environment Variables:
 * - PORT: Server port (default: 3000)
 * - HOST: Server host (default: 0.0.0.0)
 * - NODE_ENV: Environment (development, production, test)
 */

import { getApp } from './index';
import { logger } from '../lib/logging/logger';

const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '0.0.0.0';

const app = getApp();

logger.info({ port: PORT, host: HOST, env: process.env.NODE_ENV }, 'Starting MMS API server');

export default {
  port: PORT,
  hostname: HOST,
  fetch: app.fetch,
};

