   191→ * Get PM schedule details by ID.
   192→ */
   193→pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
   194→  const requestId = getRequestId(c);
   195→  const pmId = c.req.param('id');
   196→
   197→  if (!isValidUuid(pmId)) {
