/**
 * Mileage Management Routes
 *
 * REST endpoints for mileage readings, anomalies, and meter events.
 * Wraps IngestionService with HTTP interface per spec 005.4.
 *
 * @see specs/005-api.md Section 5.4
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getIngestionService,
  type MileageReadingFilters,
  type AnomalyQueryFilters,
  type DbAnomalyType,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let ingestionService: ReturnType<typeof getIngestionService> | null = null;

function getService(): ReturnType<typeof getIngestionService> {
  if (!ingestionService) {
    ingestionService = getIngestionService();
  }
  return ingestionService;
}

export const mileageRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /mileage/readings
 *
 * Get mileage readings with filtering.
 *
 * Query Parameters:
 * - trainId: Filter by train UUID
 * - fromDate: Start date (inclusive, YYYY-MM-DD)
 * - toDate: End date (inclusive, YYYY-MM-DD)
 * - validationStatus: Filter by validation status (PENDING, VALID, ANOMALY, CORRECTED)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 */
mileageRoutes.get('/mileage/readings', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query filters
  const filters: MileageReadingFilters = {};

  const trainId = c.req.query('trainId');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');
  const validationStatus = c.req.query('validationStatus');

  if (trainId) {
    if (!isValidUuid(trainId)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid trainId format', requestId),
        400
      );
    }
    filters.trainId = trainId;
  }

  if (fromDate) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(fromDate)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format (expected YYYY-MM-DD)', requestId),
        400
      );
    }
    filters.fromDate = fromDate;
  }

  if (toDate) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(toDate)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format (expected YYYY-MM-DD)', requestId),
        400
      );
    }
    filters.toDate = toDate;
  }

  if (validationStatus) {
    const validStatuses = ['PENDING', 'VALID', 'ANOMALY', 'CORRECTED'] as const;
    if (!validStatuses.includes(validationStatus as (typeof validStatuses)[number])) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          `Invalid validationStatus. Must be one of: ${validStatuses.join(', ')}`,
          requestId
        ),
        400
      );
    }
    filters.validationStatus = validationStatus as 'PENDING' | 'VALID' | 'ANOMALY' | 'CORRECTED';
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  filters.page = pagination.page;
  filters.pageSize = pagination.pageSize;

  const result = await service.getMileageReadings(filters);

  return c.json(
    paginatedSuccess(
      result.data,
      {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /mileage/anomalies
 *
 * Get mileage anomalies requiring review.
 *
 * Query Parameters:
 * - trainId: Filter by train UUID
 * - fromDate: Start date (inclusive, YYYY-MM-DD)
 * - toDate: End date (inclusive, YYYY-MM-DD)
 * - anomalyType: Filter by anomaly type (NEGATIVE, SPIKE, DUPLICATE, MISSING, FUTURE_DATE, UNKNOWN_TRAIN)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 */
mileageRoutes.get('/mileage/anomalies', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query filters
  const filters: AnomalyQueryFilters = {};

  const trainId = c.req.query('trainId');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');
  const anomalyType = c.req.query('anomalyType');

  if (trainId) {
    if (!isValidUuid(trainId)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid trainId format', requestId),
        400
      );
    }
    filters.trainId = trainId;
  }

  if (fromDate) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(fromDate)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format (expected YYYY-MM-DD)', requestId),
        400
      );
    }
    filters.fromDate = fromDate;
  }

  if (toDate) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(toDate)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format (expected YYYY-MM-DD)', requestId),
        400
      );
    }
    filters.toDate = toDate;
  }

  if (anomalyType) {
    // Only database-stored anomaly types are queryable
    const validTypes = ['NEGATIVE', 'SPIKE', 'DUPLICATE', 'MISSING'] as const;
    if (!validTypes.includes(anomalyType as (typeof validTypes)[number])) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          `Invalid anomalyType. Must be one of: ${validTypes.join(', ')}`,
          requestId
        ),
        400
      );
    }
    filters.anomalyType = anomalyType as DbAnomalyType;
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  filters.page = pagination.page;
  filters.pageSize = pagination.pageSize;

  const result = await service.getAnomalies(filters);

  return c.json(
    paginatedSuccess(
      result.data,
      {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * POST /mileage/meter-events
 *
 * Record a meter event (swap, replacement, calibration).
 *
 * Request Body:
 * {
 *   trainId: string (UUID),
 *   eventDate: string (YYYY-MM-DD),
 *   eventType: 'REPLACEMENT' | 'RESET' | 'CALIBRATION' | 'SWAP',
 *   oldMeterSerial?: string,
 *   newMeterSerial?: string,
 *   oldMeterReading: number,
 *   newMeterReading: number,
 *   reason?: string
 * }
 */
mileageRoutes.post('/mileage/meter-events', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  let body: unknown;
  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  // Validate required fields
  const data = body as Record<string, unknown>;

  if (!data.trainId || typeof data.trainId !== 'string') {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'trainId is required and must be a string', requestId),
      400
    );
  }

  if (!isValidUuid(data.trainId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid trainId format', requestId),
      400
    );
  }

  if (!data.eventDate || typeof data.eventDate !== 'string') {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'eventDate is required and must be a string', requestId),
      400
    );
  }

  if (!/^\d{4}-\d{2}-\d{2}$/.test(data.eventDate)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid eventDate format (expected YYYY-MM-DD)', requestId),
      400
    );
  }

  if (!data.eventType || typeof data.eventType !== 'string') {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'eventType is required and must be a string', requestId),
      400
    );
  }

  const validEventTypes = ['REPLACEMENT', 'RESET', 'CALIBRATION', 'SWAP'] as const;
  if (!validEventTypes.includes(data.eventType as (typeof validEventTypes)[number])) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `Invalid eventType. Must be one of: ${validEventTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  if (typeof data.oldMeterReading !== 'number' || data.oldMeterReading < 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'oldMeterReading is required and must be a non-negative number', requestId),
      400
    );
  }

  if (typeof data.newMeterReading !== 'number' || data.newMeterReading < 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'newMeterReading is required and must be a non-negative number', requestId),
      400
    );
  }

  const reason = typeof data.reason === 'string' ? data.reason : undefined;

  // Get user ID from auth context (if available)
  const user = c.get('user');
  const createdBy = user?.id;

  const meterEvent = await service.createMeterEvent(
    data.trainId,
    data.eventType as 'REPLACEMENT' | 'RESET' | 'CALIBRATION' | 'SWAP',
    data.eventDate,
    data.oldMeterReading,
    data.newMeterReading,
    reason,
    createdBy
  );

  return c.json(
    success(meterEvent, {
      timing: { durationMs: getRequestDuration(c) },
    }),
    201
  );
});

/**
 * GET /mileage/stats
 *
 * Get ingestion statistics for the specified time period.
 *
 * Query Parameters:
 * - days: Number of days to look back (default: 7)
 */
mileageRoutes.get('/mileage/stats', async (c) => {
  const service = getService();

  const daysParam = c.req.query('days');
  const days = daysParam ? Math.max(1, Math.min(365, Number(daysParam) || 7)) : 7;

  const stats = await service.getIngestionStats(days);

  return c.json(
    success(stats, {
      timing: { durationMs: getRequestDuration(c) },
    })
  );
});

/**
 * GET /mileage/health
 *
 * Check mileage file ingestion health.
 *
 * Returns whether files have been received within the expected timeframe.
 */
mileageRoutes.get('/mileage/health', async (c) => {
  const service = getService();

  const health = await service.checkFileArrivalHealth();

  return c.json(
    success(health, {
      timing: { durationMs: getRequestDuration(c) },
    })
  );
});

