 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 20, max: 100)
 * - sortBy: Sort field (createdAt, confidenceLevel, trainNumber)
 * - sortOrder: Sort direction (asc, desc) - default: asc (oldest first)
 */
baselineAssumptionRoutes.get('/baseline-assumptions/review-queue', async (c) => {
  const service = getService();

  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sortBy')
      ? `${c.req.query('sortBy')}:${c.req.query('sortOrder') ?? 'asc'}`
      : undefined,
  });

  const result = await service.getReviewQueue({
    page: pagination.page,
    pageSize: Math.min(pagination.pageSize, 100),
    sortBy: (c.req.query('sortBy') as 'createdAt' | 'confidenceLevel' | 'trainNumber') ?? 'createdAt',
    sortOrder: (c.req.query('sortOrder') as 'asc' | 'desc') ?? 'asc',
  });

  return c.json(
    paginatedSuccess(
