import { getRequestId } from './request-context';
import { addUserContextToSpan } from './tracing';
import { error, ErrorCodes } from '../types';
import { AuthorizationError } from '../../lib/errors';
import type { JwtPayload } from '../../services/auth';

/**
 * JWT secret - must match AuthService
 */
const JWT_SECRET = process.env.JWT_SECRET || 'mms-development-secret-change-in-production';

/** JWT signing algorithm */
const JWT_ALGORITHM = 'HS256' as const;

/**
 * Get authenticated user from context
 */
export function getAuthUser(c: Context<{ Variables: AppVariables }>): AuthUser | undefined {
  return c.get('user');
}

/**
 * Require authenticated user - throws if not present
 */
export function requireAuthUser(c: Context<{ Variables: AppVariables }>): AuthUser {
  const user = c.get('user');
  if (!user) {
    throw new AuthorizationError('Authentication required');
  }
  return user;
}

