 * Authentication middleware
 *
 * Validates Bearer token in Authorization header and populates user context.
 * Call this before any route handler that requires authentication.
 */
export function authMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<Response | void> => {
    const requestId = getRequestId(c);
    const authHeader = c.req.header('authorization');

    // Check for Authorization header
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
