/**
 * MMS WebSocket Hub Types
 *
 * Type definitions for WebSocket message protocols, events, and payloads.
 * Implements real-time communication for canvas updates, optimizer progress,
 * and collaborative editing.
 *
 * @see specs/005-api.md Section 5.14 (WebSocket Events)
 */

// =============================================================================
// Base Message Types
// =============================================================================

/** Direction of WebSocket messages */
export type MessageDirection = 'client-to-server' | 'server-to-client' | 'bidirectional';

/** Base WebSocket message structure */
export interface WebSocketMessage<T = unknown> {
  type: string;
  data?: T;
  timestamp?: string;
  correlationId?: string;
}

// =============================================================================
// Client → Server Messages
// =============================================================================

/** Authentication request sent after connection */
export interface AuthMessage extends WebSocketMessage<{ token: string }> {
  type: 'AUTH';
  data: { token: string };
}

/** Subscribe to canvas region updates */
export interface CanvasSubscribeMessage extends WebSocketMessage<CanvasSubscriptionRegion> {
  type: 'canvas:subscribe';
  data: CanvasSubscriptionRegion;
}

/** Unsubscribe from canvas region updates */
export interface CanvasUnsubscribeMessage extends WebSocketMessage<{ subscriptionId: string }> {
  type: 'canvas:unsubscribe';
  data: { subscriptionId: string };
}

/** Request to move a PM via drag-and-drop */
export interface MovePmRequest extends WebSocketMessage<MovePmRequestData> {
  type: 'canvas:move_pm';
  data: MovePmRequestData;
}

/** Ping message for keepalive */
export interface PingMessage extends WebSocketMessage<void> {
  type: 'ping';
}

// =============================================================================
// Server → Client Messages
// =============================================================================

/** Authentication result */
export interface AuthResultMessage extends WebSocketMessage<AuthResultData> {
  type: 'AUTH_RESULT';
  data: AuthResultData;
}

/** PM schedule updated event */
export interface PmUpdatedEvent extends WebSocketMessage<PmUpdatedData> {
  type: 'canvas:pm_updated';
  data: PmUpdatedData;
}

/** PM lock/unlock event */
export interface PmLockedEvent extends WebSocketMessage<PmLockedData> {
  type: 'canvas:pm_locked';
  data: PmLockedData;
}

/** Man-hour projections updated event */
export interface ManhourUpdatedEvent extends WebSocketMessage<ManhourUpdatedData> {
  type: 'canvas:manhour_updated';
  data: ManhourUpdatedData;
}

/** Drift analysis updated event */
export interface DriftUpdatedEvent extends WebSocketMessage<DriftUpdatedData> {
  type: 'canvas:drift_updated';
  data: DriftUpdatedData;
}

/** Optimizer job progress event */
export interface OptimizerProgressEvent extends WebSocketMessage<OptimizerProgressData> {
  type: 'optimizer:progress';
  data: OptimizerProgressData;
}

/** Optimizer job complete event */
export interface OptimizerCompleteEvent extends WebSocketMessage<OptimizerCompleteData> {
  type: 'optimizer:complete';
  data: OptimizerCompleteData;
}

/** PM move result */
export interface MovePmResultMessage extends WebSocketMessage<MovePmResultData> {
  type: 'canvas:move_pm_result';
  data: MovePmResultData;
}

/** Subscription confirmed */
export interface SubscriptionConfirmedMessage extends WebSocketMessage<SubscriptionConfirmedData> {
  type: 'canvas:subscription_confirmed';
  data: SubscriptionConfirmedData;
}

/** Pong response to ping */
export interface PongMessage extends WebSocketMessage<void> {
  type: 'pong';
}

/** Error message */
export interface ErrorMessage extends WebSocketMessage<ErrorData> {
  type: 'error';
  data: ErrorData;
}

// =============================================================================
// Data Payloads
// =============================================================================

/** Canvas subscription region */
export interface CanvasSubscriptionRegion {
  trainIds?: string[];
  depotIds?: string[];
  fromDate: string;
  toDate: string;
  zoomLevel: 'STRATEGIC' | 'TACTICAL' | 'OPERATIONAL';
}

/** PM move request data */
export interface MovePmRequestData {
  pmId: string;
  newTargetDate: string;
  newTrackId?: string;
}

/** Auth result data */
export interface AuthResultData {
  success: boolean;
  userId?: string;
  displayName?: string;
  error?: string;
}

/** PM updated event data */
export interface PmUpdatedData {
  pmId: string;
  trainId: string;
  trainNumber: string;
  changes: Array<{
    field: string;
    oldValue: unknown;
    newValue: unknown;
  }>;
  changedBy: {
    userId: string;
    displayName: string;
  };
}

/** PM locked event data */
export interface PmLockedData {
  pmId: string;
  trainId: string;
  trainNumber: string;
  isLocked: boolean;
  lockedBy?: {
    userId: string;
    displayName: string;
  };
  lockedReason?: string;
}

/** Man-hour updated event data */
export interface ManhourUpdatedData {
  depotId: string;
  depotCode: string;
  periodStart: string;
  periodEnd: string;
  requiredHours: number;
  availableHours: number;
  utilizationPct: number;
  isOverloaded: boolean;
}

/** Drift updated event data */
export interface DriftUpdatedData {
  baselineId: string;
  baselineName: string;
  analysisDate: string;
  summary: {
    totalTrains: number;
    trainsWithDrift: number;
    trainsRequiringReplan: number;
    avgFleetDriftPct: number;
  };
  affectedTrainIds: string[];
}

/** Optimizer progress data */
export interface OptimizerProgressData {
  jobId: string;
  percent: number;
  currentObjective: number;
  feasible: boolean;
  elapsedMs: number;
}

/** Optimizer complete data */
export interface OptimizerCompleteData {
  jobId: string;
  status: 'OPTIMAL' | 'FEASIBLE' | 'INFEASIBLE' | 'TIMEOUT' | 'ERROR';
  solveTimeMs: number;
  assignmentCount?: number;
  unassignedCount?: number;
  error?: string;
}

/** PM move result data */
export interface MovePmResultData {
  success: boolean;
  pmId: string;
  newTargetDate?: string;
  newTrackId?: string;
  error?: {
    code: 'MAXIMO_LOCK' | 'OUTSIDE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL_BLOCK' | 'BASELINE_LOCK' | 'UNAUTHORIZED' | 'NOT_FOUND' | 'INTERNAL_ERROR';
    message: string;
    suggestion?: string;
    maximoStatus?: string;
  };
}

/** Subscription confirmed data */
export interface SubscriptionConfirmedData {
  subscriptionId: string;
  region: CanvasSubscriptionRegion;
  trainCount: number;
}

/** Error data */
export interface ErrorData {
  code: string;
  message: string;
  details?: unknown;
}

// =============================================================================
// Union Types
// =============================================================================

/** All client-to-server message types */
export type ClientMessage =
  | AuthMessage
  | CanvasSubscribeMessage
  | CanvasUnsubscribeMessage
  | MovePmRequest
  | PingMessage;

/** All server-to-client message types */
export type ServerMessage =
  | AuthResultMessage
  | PmUpdatedEvent
  | PmLockedEvent
  | ManhourUpdatedEvent
  | DriftUpdatedEvent
  | OptimizerProgressEvent
  | OptimizerCompleteEvent
  | MovePmResultMessage
  | SubscriptionConfirmedMessage
  | PongMessage
  | ErrorMessage;

/** All message types */
export type AnyMessage = ClientMessage | ServerMessage;

// =============================================================================
// Connection Types
// =============================================================================

/** WebSocket connection state */
export type ConnectionState = 'connecting' | 'authenticating' | 'authenticated' | 'disconnected';

/** Client connection metadata */
export interface ClientConnection {
  id: string;
  userId?: string;
  displayName?: string;
  roles?: string[];
  depotId?: string;
  state: ConnectionState;
  subscriptions: Map<string, CanvasSubscriptionRegion>;
  connectedAt: Date;
  lastActivityAt: Date;
  ipAddress?: string;
  userAgent?: string;
}

/** Room for broadcasting events */
export interface Room {
  id: string;
  type: 'canvas' | 'optimizer' | 'depot';
  clients: Set<string>;
  metadata?: Record<string, unknown>;
}

